&#39;) def print_conference(x, out): title = x[&#39;title&#39;].capitalize() out.write(&#39;1. &#39;) # if title in jtitle: # out.write(&#39;[[Link to journal ver](#j&#39; + jtitle[title] + &#39;)]&#39;) out.write(&#39;, &#39;.join(x[&#39;author&#39;]) + &#39;. &#39;) out.write(title + &#39;. &#39;) out.write(&#39;_&#39; + x[&#39;booktitle&#39;] + &#39;_. &#39;) out.write(x[&#39;place&#39;] + &#39;. &#39;) if &#39;series&#39; in x: out.write(x[&#39;series&#39;] + &#39;, &#39; + x[&#39;volume&#39;] + &#39;, pp. &#39; + x[&#39;pages&#39;]) else: out.write(&#39;accepted. &#39;) out.write(x[&#39;year&#39;] + &#39;, &#39; + x[&#39;month&#39;] + &#39;. &#39;) if &#39;doi&#39; in x: out.write(&#34;[[📖doi link](&#34;+ x[&#39;doi&#39;] +&#34;)]&#34;) if &#39;arxiv&#39; in x: out.write(&#34;[[📝arXiv](&#34;+ x[&#39;arxiv&#39;] +&#34;)]&#34;) out.write(&#39;
&#39;) def print_domestic(x, out): out.write(&#39;1. &#39;) # pp = x[&#39;presenter&#39;] out.write(&#39;, &#39;.join(x[&#39;author&#39;]) + &#39;. &#39;) out.write(x[&#39;title&#39;].capitalize() + &#39;. &#39;) out.write(&#39;, &#39;.join(x[&#39;booktitle&#39;]) + &#39;.
&#39;) with open(outjp, mode=&#39;w&#39;) as wjp, open(outen, mode=&#39;w&#39;) as wen: wjp.write( &#39;---
title: &#34;研究成果&#34;
summary: &#34;研究成果&#34;
date: &#39; + datetime.datetime.now().strftime(&#34;%Y-%m-%dT%H:%M:%S+09:00&#34;) + &#39;
---
&#39; ) wen.write( &#39;---
title: &#34;My publications&#34;
summary: &#34;My publications&#34;
date: &#39; + datetime.datetime.now().strftime(&#34;%Y-%m-%dT%H:%M:%S+09:00&#34;) + &#39;
---
&#39; ) with open(publication_db, mode=&#39;r&#39;) as cdb: db = yaml.safe_load(cdb) wjp.write(&#34;### Journal papers
&#34;) wen.write(&#34;### Journal papers
&#34;) for x in db[&#34;journal&#34;]: print_journal(x, wjp) print_journal(x, wen) wjp.write(&#34;### Conference papers
&#34;) wen.write(&#34;### Conference papers
&#34;) for x in db[&#34;conference&#34;]: print_conference(x, wjp) print_conference(x, wen) wjp.write(&#34;### 国内研究会発表
&#34;) for x in db[&#34;domestic&#34;]: print_domestic(x, wjp) ( hugo の python のハイライトがうまくいかないな…)
